"""
Parameterized generator for GH561_flagsmith_6929.

Source PR:    https://github.com/Flagsmith/flagsmith/pull/6929
Source Issue: https://github.com/Flagsmith/flagsmith/issues/6914

Seed varies: renames 'a_wild_pokemon' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH561_flagsmith_6929'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH561_flagsmith_6929'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('a_wild_pokemon', 'a_wild_pokemon' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH561_flagsmith_6929',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'Flagsmith/flagsmith',
                "pr_number": 6929,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/Flagsmith/flagsmith/pull/6929",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'api/segments/serializers.py': 'from typing import Any\n\nimport structlog\nfrom django.conf import settings\nfrom django.db import transaction\nfrom drf_writable_nested.serializers import WritableNestedModelSerializer\nfrom rest_framework import serializers\nfrom rest_framework.exceptions import ValidationError\n\nfrom metadata.serializers import MetadataSerializer, MetadataSerializerMixin\nfrom projects.models import Project\nfrom segments.models import Condition, Segment, SegmentRule\n\nlogger = structlog.get_logger()\n\nDictList = list[dict[str, Any]]\n\n\nclass ConditionSerializer(serializers.ModelSerializer[Condition]):\n    delete = serializers.BooleanField(\n        write_only=True,\n        required=False,\n    )\n\n    class Meta:\n        model = Condition\n        fields = [\n            "id",\n            "operator",\n            "property",\n            "value",\n            "description",\n            "delete",\n        ]\n\n    def to_internal_value(self, data: dict[str, Any]) -> Any:\n        # Conversion to correct value type is handled elsewhere\n        data["value"] = str(data["value"]) if "value" in data else None\n        return super().to_internal_value(data)\n\n\nclass _BaseSegmentRuleSerializer(WritableNestedModelSerializer):\n    delete = serializers.BooleanField(\n        write_only=True,\n        required=False,\n    )\n    conditions = ConditionSerializer(\n        many=True,\n        required=False,\n    )\n\n\nclass _NestedSegmentRuleSerializer(_BaseSegmentRuleSerializer):\n    class Meta:\n        model = SegmentRule\n        fields = [\n            "id",\n            "type",\n            "conditions",\n            "delete",\n        ]\n\n\nclass SegmentRuleSerializer(_BaseSegmentRuleSerializer):\n    rules = _NestedSegmentRuleSerializer(\n        many=True,\n        required=False,\n    )\n\n    class Meta:\n        model = SegmentRule\n        fields = [\n            "id",\n            "type",\n            "rules",\n            "conditions",\n            "delete",\n        ]\n\n\nclass SegmentSerializer(MetadataSerializerMixin, WritableNestedModelSerializer):\n    rules = SegmentRuleSerializer(many=True, required=True, allow_empty=False)\n    metadata = MetadataSerializer(required=False, many=True)\n\n    def __init__(self, *args: Any, **kwargs: Any) -> None:\n        """\n        Because WritableNestedModelSerializer uses `initial_data` instead of `data`\n        we need to override the `__init__` method to remove rules and conditions\n        that are marked for deletion.\n        """\n        data = kwargs.get("data")\n        if data and "rules" in data:\n            data["rules"] = self._get_rules_and_conditions_without_deleted(\n                data["rules"]\n            )\n            kwargs["data"] = data\n\n        super().__init__(*args, **kwargs)\n\n    class Meta:\n        model = Segment\n        fields = [\n            "id",\n            "uuid",\n            "created_at",\n            "updated_at",\n            "name",\n            "description",\n            "project",\n            "feature",\n            "version_of",\n            "rules",\n            "metadata",\n        ]\n\n    def validate(self, attrs: dict[str, Any]) -> dict[str, Any]:\n        attrs = super().validate(attrs)\n        project = self.instance.project if self.instance else attrs["project"]  # type: ignore[union-attr]\n        organisation = project.organisation\n\n        self._validate_required_metadata(\n            organisation, attrs.get("metadata", []), project=project\n        )\n        self._validate_segment_rules_conditions_limit(attrs["rules"])\n        self._validate_project_segment_limit(project)\n        return attrs\n\n    def create(self, validated_data: dict[str, Any]):  # type: ignore[no-untyped-def]\n        metadata_data = validated_data.pop("metadata", [])\n        segment = super().create(validated_data)  # type: ignore[no-untyped-call]\n        self._update_metadata(segment, metadata_data)\n        return segment\n\n    def update(self, segment: Segment, validated_data: dict[str, Any]):  # type: ignore[no-untyped-def]\n        metadata = validated_data.pop("metadata", [])\n        with transaction.atomic():\n            if not segment.change_request:\n                segment_revision = segment.clone(is_revision=True)\n                logger.info(\n                    "segment-revision-created",\n                    segment_id=segment.id,\n                    revision_id=segment_revision.id,\n                )\n            segment = super().update(segment, validated_data)  # type: ignore[no-untyped-call]\n        self._update_metadata(segment, metadata)\n        return segment\n\n    def _get_rules_and_conditions_without_deleted(\n        self, rules_data: DictList\n    ) -> DictList:\n        """\n        Remove rules and conditions marked for deletion from input\n\n        NOTE: This is to support previous API design, in which any nested rules\n        or conditions including both an `"id"` field and `"delete": true` were\n        later soft-deleted in the database.\n\n        TODO: Deprecate this in favor of not sending unwanted rules and\n        conditions in the input.\n        """\n        return [\n            {\n                **rule_data,\n                "conditions": [\n                    condition_data\n                    for condition_data in rule_data.get("conditions", [])\n                    if not condition_data.get("delete")\n                ],\n                "rules": self._get_rules_and_conditions_without_deleted(\n                    rule_data.get("rules", [])\n                ),\n            }\n            for rule_data in rules_data\n            if not rule_data.get("delete")\n        ]\n\n    def _validate_project_segment_limit(self, project: Project) -> None:\n        segment_count = Segment.live_objects.filter(project=project).count()\n        if segment_count >= project.max_segments_allowed:\n            raise ValidationError(\n                {\n                    "project": "The project has reached the maximum allowed segments limit."\n                }\n            )\n\n    def _validate_segment_rules_conditions_limit(self, rules_data: DictList) -> None:\n        if self.instance and getattr(self.instance, "whitelisted_segment", None):\n            return\n\n        def _count_conditions(rules_data: DictList) -> int:\n            return sum(\n                len(rule.get("conditions", []))\n                + _count_conditions(rule.get("rules", []))\n                for rule in rules_data\n            )\n\n        condition_count = _count_conditions(rules_data)\n        if condition_count > settings.SEGMENT_RULES_CONDITIONS_LIMIT:\n            raise ValidationError(\n                {\n                    "segment": f"The segment has {condition_count} conditions, which exceeds the maximum condition count of {settings.SEGMENT_RULES_CONDITIONS_LIMIT}."\n                }\n            )\n\n\nclass SegmentSerializerBasic(serializers.ModelSerializer):  # type: ignore[type-arg]\n    class Meta:\n        model = Segment\n        fields = ("id", "name", "description")\n\n\nclass SegmentListQuerySerializer(serializers.Serializer):  # type: ignore[type-arg]\n    q = serializers.CharField(\n        required=False,\n        help_text="Search term to find segment with given term in their name",\n    )\n    identity = serializers.CharField(\n        required=False,\n        help_text="Optionally provide the id of an identity to get only the segments they match",\n    )\n    include_feature_specific = serializers.BooleanField(required=False, default=True)\n\n\nclass CloneSegmentSerializer(serializers.ModelSerializer[Segment]):\n    class Meta:\n        model = Segment\n        fields = ("name",)\n',
            'api/segments/views.py': 'import logging\nfrom typing import Any\n\nfrom common.projects.permissions import VIEW_PROJECT\nfrom django.utils.decorators import method_decorator\nfrom drf_spectacular.utils import extend_schema\nfrom rest_framework import status, viewsets\nfrom rest_framework.decorators import action, api_view\nfrom rest_framework.generics import get_object_or_404\nfrom rest_framework.request import Request\nfrom rest_framework.response import Response\n\nfrom app.pagination import CustomPagination\nfrom core.dataclasses import AuthorData\nfrom edge_api.identities.models import EdgeIdentity\nfrom environments.identities.models import Identity\nfrom environments.models import Environment\nfrom features.models import FeatureState\nfrom features.serializers import (\n    AssociatedFeaturesQuerySerializer,\n    SegmentAssociatedFeatureStateSerializer,\n)\nfrom features.versioning.models import EnvironmentFeatureVersion\n\nfrom .models import Segment\nfrom .permissions import SegmentPermissions\nfrom .serializers import (\n    CloneSegmentSerializer,\n    SegmentListQuerySerializer,\n    SegmentSerializer,\n)\nfrom .services import delete_segment\n\nlogger = logging.getLogger()\n\n\n@method_decorator(\n    name="list",\n    decorator=extend_schema(\n        tags=["mcp"],\n        parameters=[SegmentListQuerySerializer],\n        extensions={\n            "x-gram": {\n                "name": "list_project_segments",\n                "description": "Retrieves all user segments defined for audience targeting within the project.",\n            },\n        },\n    ),\n)\n@method_decorator(\n    name="create",\n    decorator=extend_schema(\n        tags=["mcp"],\n        extensions={\n            "x-gram": {\n                "name": "create_project_segment",\n                "description": "Creates a new user segment for audience targeting within the project.",\n            },\n        },\n    ),\n)\n@method_decorator(\n    name="retrieve",\n    decorator=extend_schema(\n        tags=["mcp"],\n        extensions={\n            "x-gram": {\n                "name": "get_project_segment",\n                "description": "Retrieves detailed information about a specific user segment.",\n            },\n        },\n    ),\n)\n@method_decorator(\n    name="update",\n    decorator=extend_schema(\n        tags=["mcp"],\n        extensions={\n            "x-gram": {\n                "name": "update_project_segment",\n                "description": "Updates an existing user segment\'s properties and rules.",\n            },\n        },\n    ),\n)\nclass SegmentViewSet(viewsets.ModelViewSet):  # type: ignore[type-arg]\n    serializer_class = SegmentSerializer\n    permission_classes = [SegmentPermissions]\n    pagination_class = CustomPagination\n\n    def get_queryset(self):  # type: ignore[no-untyped-def]\n        if getattr(self, "swagger_fake_view", False):\n            return Segment.objects.none()\n\n        permitted_projects = self.request.user.get_permitted_projects(  # type: ignore[union-attr]\n            permission_key=VIEW_PROJECT\n        )\n        project = get_object_or_404(permitted_projects, pk=self.kwargs["project_pk"])\n\n        queryset = Segment.live_objects.filter(project=project, is_system_segment=False)\n\n        if self.action == "list":\n            # TODO: at the moment, the UI only shows the name and description of the segment in the list view.\n            #  we shouldn\'t return all of the rules and conditions in the list view.\n            queryset = queryset.prefetch_related(\n                "rules",\n                "rules__conditions",\n                "rules__rules",\n                "rules__rules__conditions",\n                "rules__rules__rules",\n                "metadata",\n            )\n\n        query_serializer = SegmentListQuerySerializer(data=self.request.query_params)\n        query_serializer.is_valid(raise_exception=True)\n\n        identity_pk = query_serializer.validated_data.get("identity")\n        if identity_pk:\n            if identity_pk.isdigit():\n                identity = Identity.objects.get(pk=identity_pk)\n                segment_ids = [segment.id for segment in identity.get_segments()]\n            else:\n                segment_ids = EdgeIdentity.dynamo_wrapper.get_segment_ids(identity_pk)\n            queryset = queryset.filter(id__in=segment_ids)\n\n        search_term = query_serializer.validated_data.get("q")\n        if search_term:\n            queryset = queryset.filter(name__icontains=search_term)\n\n        include_feature_specific = query_serializer.validated_data[\n            "include_feature_specific"\n        ]\n        if include_feature_specific is False:\n            queryset = queryset.filter(feature__isnull=True)\n\n        return queryset\n\n    @extend_schema(parameters=[AssociatedFeaturesQuerySerializer])\n    @action(\n        detail=True,\n        methods=["GET"],\n        url_path="associated-features",\n        serializer_class=SegmentAssociatedFeatureStateSerializer,\n    )\n    def associated_features(self, request, *args, **kwargs):  # type: ignore[no-untyped-def]\n        segment = self.get_object()\n\n        query_serializer = AssociatedFeaturesQuerySerializer(data=request.query_params)\n        query_serializer.is_valid(raise_exception=True)\n\n        filter_kwargs = {"feature_segment__segment": segment}\n        if environment_id := query_serializer.validated_data.get("environment"):\n            environment = Environment.objects.get(pk=environment_id)\n            filter_kwargs["environment"] = environment\n            if environment.use_v2_feature_versioning:\n                filter_kwargs["environment_feature_version__in"] = (\n                    EnvironmentFeatureVersion.objects.get_latest_versions_by_environment_id(\n                        environment_id\n                    )\n                )\n\n        queryset = FeatureState.objects.filter(**filter_kwargs)\n\n        page = self.paginate_queryset(queryset)\n        if page is not None:\n            serializer = self.get_serializer(page, many=True)\n            return self.get_paginated_response(serializer.data)\n\n        serializer = self.get_serializer(queryset, many=True)\n        return Response(serializer.data)\n\n    def destroy(self, request: Request, *args: Any, **kwargs: Any) -> Response:\n        segment = self.get_object()\n        author = AuthorData.from_request(request)\n        delete_segment(segment, author=author)\n        return Response(status=status.HTTP_204_NO_CONTENT)\n\n    @extend_schema(\n        request=CloneSegmentSerializer,\n        responses={201: SegmentSerializer},\n    )\n    @action(\n        detail=True,\n        methods=["POST"],\n        url_path="clone",\n        serializer_class=CloneSegmentSerializer,\n    )\n    def clone(self, request: Request, *args: Any, **kwargs: Any) -> Response:\n        source_segment = self.get_object()\n        serializer = CloneSegmentSerializer(data=request.data)\n        serializer.is_valid(raise_exception=True)\n        clone = source_segment.clone(name=serializer.validated_data["name"])\n        return Response(SegmentSerializer(clone).data, status=status.HTTP_201_CREATED)\n\n\n@extend_schema(responses={200: SegmentSerializer})\n@api_view(["GET"])\ndef get_segment_by_uuid(request, uuid):  # type: ignore[no-untyped-def]\n    accessible_projects = request.user.get_permitted_projects(VIEW_PROJECT)\n    qs = Segment.live_objects.filter(project__in=accessible_projects)\n    segment = get_object_or_404(qs, uuid=uuid)\n    serializer = SegmentSerializer(instance=segment)\n    return Response(serializer.data)\n',
            'api/tests/unit/segments/test_unit_segments_views.py': 'import json\nimport random\n\nimport pytest\nfrom common.projects.permissions import (\n    MANAGE_SEGMENTS,\n    VIEW_PROJECT,\n)\nfrom django.conf import settings\nfrom django.contrib.auth import get_user_model\nfrom django.contrib.contenttypes.models import ContentType\nfrom django.urls import reverse\nfrom flag_engine.segments.constants import EQUAL\nfrom pytest_django import DjangoAssertNumQueries\nfrom pytest_django.fixtures import SettingsWrapper\nfrom pytest_lazyfixture import lazy_fixture  # type: ignore[import-untyped]\nfrom pytest_mock import MockerFixture\nfrom rest_framework import status\nfrom rest_framework.test import APIClient\n\nfrom audit.constants import SEGMENT_DELETED_MESSAGE\nfrom audit.models import AuditLog\nfrom audit.related_object_type import RelatedObjectType\nfrom environments.models import Environment\nfrom features.models import Feature, FeatureSegment, FeatureState\nfrom features.versioning.models import EnvironmentFeatureVersion\nfrom metadata.models import (\n    Metadata,\n    MetadataField,\n    MetadataModelField,\n    MetadataModelFieldRequirement,\n)\nfrom organisations.models import Organisation\nfrom projects.models import Project\nfrom segments.models import Condition, Segment, SegmentRule, WhitelistedSegment\nfrom tests.types import WithProjectPermissionsCallable\nfrom util.mappers import map_identity_to_identity_document\n\nUser = get_user_model()\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_can_filter_by_identity_to_get_only_matching_segments(  # type: ignore[no-untyped-def]\n    project, client, environment, identity, trait, identity_matching_segment, segment\n):\n    # Given\n    base_url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n    url = base_url + "?identity=%d" % identity.id\n\n    # When\n    res = client.get(url)\n\n    # Then\n    assert res.json().get("count") == 1\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_cannot_create_segments_without_rules(project, client):  # type: ignore[no-untyped-def]\n    # Given\n    url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n    data = {"name": "New segment name", "project": project.id, "rules": []}\n\n    # When\n    res = client.post(url, data=json.dumps(data), content_type="application/json")\n\n    # Then\n    assert res.status_code == status.HTTP_400_BAD_REQUEST\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_can_create_segments_with_boolean_condition(project, client):  # type: ignore[no-untyped-def]\n    # Given\n    url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n    data = {\n        "name": "New segment name",\n        "project": project.id,\n        "rules": [\n            {\n                "type": "ALL",\n                "rules": [],\n                "conditions": [\n                    {"operator": EQUAL, "property": "test-property", "value": True}\n                ],\n            }\n        ],\n    }\n\n    # When\n    res = client.post(url, data=json.dumps(data), content_type="application/json")\n\n    # Then\n    assert res.status_code == status.HTTP_201_CREATED\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_can_not_create_system_segment(project: Project, client: APIClient):  # type: ignore[no-untyped-def]\n    # Given\n    url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n    data = {\n        "name": "New segment name",\n        "project": project.id,\n        "is_system_segment": True,\n        "rules": [\n            {\n                "type": "ALL",\n                "rules": [],\n                "conditions": [\n                    {"operator": EQUAL, "property": "test-property", "value": True}\n                ],\n            }\n        ],\n    }\n\n    # When\n    res = client.post(url, data=json.dumps(data), content_type="application/json")\n\n    # Then\n    assert res.status_code == status.HTTP_201_CREATED\n    assert "is_system_segment" not in res.json()\n    assert (\n        Segment.objects.filter(id=res.json()["id"], is_system_segment=True).exists()\n        is False\n    )\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_can_create_segments_with_condition_that_has_null_value(project, client):  # type: ignore[no-untyped-def]\n    # Given\n    url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n    data = {\n        "name": "New segment name",\n        "project": project.id,\n        "rules": [\n            {\n                "type": "ALL",\n                "rules": [],\n                "conditions": [{"operator": EQUAL, "property": "test-property"}],\n            }\n        ],\n    }\n\n    # When\n    res = client.post(url, data=json.dumps(data), content_type="application/json")\n\n    # Then\n    assert res.status_code == status.HTTP_201_CREATED\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_create_segments_reaching_max_limit(project, client, settings):  # type: ignore[no-untyped-def]\n    # Given\n    # let\'s reduce the max segments allowed to 1\n    project.max_segments_allowed = 1\n    project.save()\n\n    url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n    data = {\n        "name": "New segment name",\n        "project": project.id,\n        "rules": [\n            {\n                "type": "ALL",\n                "rules": [],\n                "conditions": [{"operator": EQUAL, "property": "test-property"}],\n            }\n        ],\n    }\n\n    # Now, let\'s create the first segment\n    res = client.post(url, data=json.dumps(data), content_type="application/json")\n    assert res.status_code == status.HTTP_201_CREATED\n\n    # Then\n    # Let\'s try to create a second segment\n    res = client.post(url, data=json.dumps(data), content_type="application/json")\n    assert res.status_code == status.HTTP_400_BAD_REQUEST\n    assert res.json()["project"] == [\n        "The project has reached the maximum allowed segments limit."\n    ]\n    assert project.segments.count() == 1\n\n\ndef test_segments_limit_ignores_old_segment_versions(\n    project: Project,\n    segment: Segment,\n    staff_client: APIClient,\n    with_project_permissions: WithProjectPermissionsCallable,\n) -> None:\n    # Given\n    with_project_permissions([MANAGE_SEGMENTS])  # type: ignore[call-arg]\n\n    # let\'s reduce the max segments allowed to 2\n    project.max_segments_allowed = 2\n    project.save()\n\n    # and create some older versions for the segment fixture\n    segment.clone(is_revision=True)\n    assert Segment.objects.filter(version_of=segment).count() == 2\n    assert Segment.live_objects.count() == 1\n\n    url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n    data = {\n        "name": "New segment name",\n        "project": project.id,\n        "rules": [\n            {\n                "type": "ALL",\n                "rules": [],\n                "conditions": [{"operator": EQUAL, "property": "test-property"}],\n            }\n        ],\n    }\n\n    # When\n    res = staff_client.post(url, data=json.dumps(data), content_type="application/json")\n\n    # Then\n    assert res.status_code == status.HTTP_201_CREATED\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_audit_log_created_when_segment_updated(\n    client: APIClient,\n    project: Project,\n    segment: Segment,\n) -> None:\n    # Given\n    url = reverse(\n        "api-v1:projects:project-segments-detail",\n        args=[project.id, segment.id],\n    )\n    data = {\n        "name": "New segment name",\n        "project": project.id,\n        "rules": [{"type": "ALL", "rules": [], "conditions": []}],\n    }\n\n    # When\n    response = client.put(url, data=json.dumps(data), content_type="application/json")\n\n    # Then\n    assert response.status_code == status.HTTP_200_OK\n\n    assert AuditLog.objects.filter(\n        related_object_type=RelatedObjectType.SEGMENT.name,\n        log="Segment updated: New segment name",\n    ).exists()\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_can_patch_segment(project, segment, client):  # type: ignore[no-untyped-def]\n    # Given\n    segment = Segment.objects.create(name="Test segment", project=project)\n    url = reverse(\n        "api-v1:projects:project-segments-detail",\n        args=[project.id, segment.id],\n    )\n    data = {\n        "name": "New segment name",\n        "rules": [{"type": "ALL", "rules": [], "conditions": []}],\n    }\n\n    # When\n    res = client.patch(url, data=json.dumps(data), content_type="application/json")\n\n    # Then\n    assert res.status_code == status.HTTP_200_OK\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_audit_log_created_when_segment_deleted(project, segment, client):  # type: ignore[no-untyped-def]\n    # Given\n    segment = Segment.objects.create(name="Test segment", project=project)\n    url = reverse(\n        "api-v1:projects:project-segments-detail",\n        args=[project.id, segment.id],\n    )\n\n    # When\n    res = client.delete(url, content_type="application/json")\n\n    # Then\n    assert res.status_code == status.HTTP_204_NO_CONTENT\n    assert (\n        AuditLog.objects.filter(\n            related_object_type=RelatedObjectType.SEGMENT.name,\n            log=SEGMENT_DELETED_MESSAGE % segment.name,\n        ).count()\n        == 1\n    )\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_cannot_delete_system_segment(\n    project: Project, system_segment: Segment, client: APIClient\n) -> None:\n    # Given\n    url = reverse(\n        "api-v1:projects:project-segments-detail",\n        args=[project.id, system_segment.id],\n    )\n\n    # When\n    res = client.delete(url, content_type="application/json")\n\n    # Then\n    assert res.status_code == status.HTTP_404_NOT_FOUND\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_audit_log_created_when_segment_created(project, client):  # type: ignore[no-untyped-def]\n    # Given\n    url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n    data = {\n        "name": "Test Segment",\n        "project": project.id,\n        "rules": [{"type": "ALL", "rules": [], "conditions": []}],\n    }\n\n    # When\n    res = client.post(url, data=json.dumps(data), content_type="application/json")\n\n    # Then\n    assert res.status_code == status.HTTP_201_CREATED\n\n    assert (\n        AuditLog.objects.filter(\n            related_object_type=RelatedObjectType.SEGMENT.name\n        ).count()\n        == 1\n    )\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_can_filter_by_edge_identity_to_get_only_matching_segments(  # type: ignore[no-untyped-def]\n    project,\n    environment,\n    identity,\n    identity_matching_segment,\n    edge_identity_dynamo_wrapper_mock,\n    client,\n):\n    # Given\n    Segment.objects.create(name="Non matching segment", project=project)\n    expected_segment_ids = [identity_matching_segment.id]\n    identity_document = map_identity_to_identity_document(identity)\n    identity_uuid = identity_document["identity_uuid"]\n    assert isinstance(identity_uuid, str)\n\n    edge_identity_dynamo_wrapper_mock.get_segment_ids.return_value = (\n        expected_segment_ids\n    )\n\n    base_url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n    url = f"{base_url}?identity={identity_uuid}"\n\n    # When\n    response = client.get(url)\n\n    # Then\n    assert response.json().get("count") == len(expected_segment_ids)\n    assert response.json()["results"][0]["id"] == expected_segment_ids[0]\n    edge_identity_dynamo_wrapper_mock.get_segment_ids.assert_called_with(identity_uuid)\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_associated_features_returns_all_the_associated_features(  # type: ignore[no-untyped-def]\n    project, environment, feature, segment, segment_featurestate, client\n):\n    # Given\n    # Firstly, let\'s create extra environment and feature to make sure we\n    # have some features that are not associated with the segment\n    Environment.objects.create(name="Another environment", project=project)\n    Feature.objects.create(name="another feature", project=project)\n\n    url = reverse(\n        "api-v1:projects:project-segments-associated-features",\n        args=[project.id, segment.id],\n    )\n    # When\n    response = client.get(url)\n\n    # Then\n    assert response.json().get("count") == 1\n    assert response.json()["results"][0]["id"] == segment_featurestate.id\n    assert response.json()["results"][0]["feature"] == feature.id\n    assert response.json()["results"][0]["environment"] == environment.id\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_associated_features_returns_only_latest_versions_of_associated_features(\n    project: Project,\n    segment: Segment,\n    environment_v2_versioning: Environment,\n    client: APIClient,\n) -> None:\n    # Given\n    # 2 features\n    feature_one = Feature.objects.create(project=project, name="feature_1")\n    feature_two = Feature.objects.create(project=project, name="feature_2")\n\n    # Now let\'s create a version for each feature with a segment override\n    for feature in (feature_one, feature_two):\n        version = EnvironmentFeatureVersion.objects.create(\n            feature=feature, environment=environment_v2_versioning\n        )\n        FeatureState.objects.create(\n            feature=feature,\n            environment=environment_v2_versioning,\n            environment_feature_version=version,\n            feature_segment=FeatureSegment.objects.create(\n                segment=segment,\n                environment=environment_v2_versioning,\n                feature=feature,\n                environment_feature_version=version,\n            ),\n        )\n        version.publish()\n\n    # And then let\'s create a third version for feature_one where we update the segment override\n    feature_1_version_3 = EnvironmentFeatureVersion.objects.create(\n        feature=feature_one, environment=environment_v2_versioning\n    )\n    f1v3_segment_override_feature_state = feature_1_version_3.feature_states.get(\n        feature_segment__segment=segment\n    )\n    f1v3_segment_override_feature_state.enabled = True\n    f1v3_segment_override_feature_state.save()\n    feature_1_version_3.publish()\n\n    # And finally, let\'s create a third version for feature_two where we remove the segment override\n    feature_2_version_3 = EnvironmentFeatureVersion.objects.create(\n        feature=feature_two, environment=environment_v2_versioning\n    )\n    feature_2_version_3.feature_states.filter(feature_segment__segment=segment).delete()\n    feature_2_version_3.publish()\n\n    url = "%s?environment=%s" % (\n        reverse(\n            "api-v1:projects:project-segments-associated-features",\n            args=[project.id, segment.id],\n        ),\n        environment_v2_versioning.id,\n    )\n\n    # When\n    response = client.get(url)\n\n    # Then\n    assert response.json().get("count") == 1\n    assert response.json()["results"][0]["id"] == f1v3_segment_override_feature_state.id\n    assert response.json()["results"][0]["feature"] == feature_one.id\n    assert response.json()["results"][0]["environment"] == environment_v2_versioning.id\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_can_create_feature_based_segment(project, client, feature):  # type: ignore[no-untyped-def]\n    # Given\n    url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n    data = {\n        "name": "Test Segment",\n        "project": project.id,\n        "feature": feature.id,\n        "rules": [{"type": "ALL", "rules": [], "conditions": []}],\n    }\n\n    # When\n    res = client.post(url, data=json.dumps(data), content_type="application/json")\n\n    # Then\n    assert res.status_code == status.HTTP_201_CREATED\n    assert res.json()["feature"] == feature.id\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_get_segment_by_uuid(client, project, segment):  # type: ignore[no-untyped-def]\n    # Given\n    url = reverse("api-v1:segments:get-segment-by-uuid", args=[segment.uuid])\n\n    # When\n    response = client.get(url)\n\n    # Then\n    assert response.status_code == status.HTTP_200_OK\n\n    assert response.json()["id"] == segment.id\n    assert response.json()["uuid"] == str(segment.uuid)\n\n\n@pytest.mark.skipif(\n    settings.IS_RBAC_INSTALLED is True,\n    reason="Skip this test if RBAC is installed",\n)\n@pytest.mark.parametrize(\n    "client, num_queries",\n    [\n        (lazy_fixture("admin_master_api_key_client"), 12),\n        (lazy_fixture("admin_client"), 14),\n    ],\n)\ndef test_list_segments_num_queries_without_rbac(\n    django_assert_num_queries: DjangoAssertNumQueries,\n    project: Project,\n    client: APIClient,\n    num_queries: int,\n    required_a_segment_metadata_field: MetadataModelField,\n) -> None:\n    # Given\n    num_segments = 5\n    _list_segment_setup_data(project, required_a_segment_metadata_field, num_segments)\n\n    # When\n    with django_assert_num_queries(num_queries):\n        # TODO: improve this\n        #  I\'ve removed the N+1 issue using prefetch related but there is still an overlap on permission checks\n        #  and we can probably use varying serializers for the segments since we only allow certain structures via\n        #  the UI (but the serializers allow for infinite nesting)\n        response = client.get(\n            reverse("api-v1:projects:project-segments-list", args=[project.id])\n        )\n\n    # Then\n    assert response.status_code == status.HTTP_200_OK\n\n    response_json = response.json()\n    assert response_json["count"] == num_segments\n\n\ndef test_system_segment_is_not_part_of_list_segments(\n    project: Project,\n    admin_client: APIClient,\n    system_segment: Segment,\n) -> None:\n    # When\n    response = admin_client.get(\n        reverse("api-v1:projects:project-segments-list", args=[project.id])\n    )\n\n    # Then\n    assert response.status_code == status.HTTP_200_OK\n\n    response_json = response.json()\n    assert response_json["count"] == 0\n    assert response_json["results"] == []\n\n\n@pytest.mark.skipif(\n    settings.IS_RBAC_INSTALLED is False,\n    reason="Skip this test if RBAC is not installed",\n)\n@pytest.mark.parametrize(\n    "client, num_queries",\n    [\n        (lazy_fixture("admin_master_api_key_client"), 12),\n        (lazy_fixture("admin_client"), 15),\n    ],\n)\ndef test_list_segments_num_queries_with_rbac(\n    django_assert_num_queries: DjangoAssertNumQueries,\n    project: Project,\n    client: APIClient,\n    num_queries: int,\n    required_a_segment_metadata_field: MetadataModelField,\n) -> None:  # pragma: no cover\n    # Given\n    num_segments = 5\n    _list_segment_setup_data(project, required_a_segment_metadata_field, num_segments)\n\n    # When\n    with django_assert_num_queries(num_queries):\n        response = client.get(\n            reverse("api-v1:projects:project-segments-list", args=[project.id])\n        )\n\n    # Then\n    assert response.status_code == status.HTTP_200_OK\n\n    response_json = response.json()\n    assert response_json["count"] == num_segments\n\n\ndef _list_segment_setup_data(\n    project: Project,\n    required_a_segment_metadata_field: MetadataModelField,\n    num_segments: int,\n) -> None:\n    for i in range(num_segments):\n        segment = Segment.objects.create(project=project, name=f"segment {i}")\n        Metadata.objects.create(\n            object_id=segment.id,\n            content_type=ContentType.objects.get_for_model(segment),\n            model_field=required_a_segment_metadata_field,\n            field_value="test",\n        )\n        all_rule = SegmentRule.objects.create(\n            segment=segment, type=SegmentRule.ALL_RULE\n        )\n        any_rule = SegmentRule.objects.create(rule=all_rule, type=SegmentRule.ANY_RULE)\n        Condition.objects.create(\n            property="foo", value=str(random.randint(0, 10)), rule=any_rule\n        )\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_search_segments(django_assert_num_queries, project, client):  # type: ignore[no-untyped-def]\n    # Given\n    segments = []\n    segment_names = ["segment one", "segment two"]\n\n    for segment_name in segment_names:\n        segment = Segment.objects.create(project=project, name=segment_name)\n        all_rule = SegmentRule.objects.create(\n            segment=segment, type=SegmentRule.ALL_RULE\n        )\n        any_rule = SegmentRule.objects.create(rule=all_rule, type=SegmentRule.ANY_RULE)\n        Condition.objects.create(\n            property="foo", value=str(random.randint(0, 10)), rule=any_rule\n        )\n        segments.append(segment)\n\n    url = "%s?q=%s" % (\n        reverse("api-v1:projects:project-segments-list", args=[project.id]),\n        segment_names[0].split()[1],\n    )\n\n    # When\n    response = client.get(url)\n\n    # Then\n    assert response.status_code == status.HTTP_200_OK\n\n    response_json = response.json()\n    assert response_json["count"] == 1\n    assert response_json["results"][0]["name"] == segment_names[0]\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_create_segments_with_description_condition(project, client):  # type: ignore[no-untyped-def]\n    # Given\n    url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n    data = {\n        "name": "New segment name",\n        "project": project.id,\n        "rules": [\n            {\n                "type": "ALL",\n                "rules": [],\n                "conditions": [\n                    {\n                        "operator": EQUAL,\n                        "property": "test-property",\n                        "value": True,\n                        "description": "test-description",\n                    }\n                ],\n            }\n        ],\n    }\n\n    # When\n    response = client.post(url, data=json.dumps(data), content_type="application/json")\n\n    # Then\n    segment_condition_description_value = response.json()["rules"][0]["conditions"][0][\n        "description"\n    ]\n    assert segment_condition_description_value == "test-description"\n\n\ndef test_update_segment_add_new_root_rule(\n    project: Project, admin_client_new: APIClient, segment: Segment\n) -> None:\n    # Given\n    url = reverse(\n        "api-v1:projects:project-segments-detail", args=[project.id, segment.id]\n    )\n    data = {\n        "name": segment.name,\n        "project": project.id,\n        "rules": [\n            {\n                "type": "ANY",\n                "rules": [\n                    {\n                        "type": "ALL",\n                        "rules": [],\n                        "conditions": [\n                            {"property": "foo", "operator": "EQUAL", "value": "bar"}\n                        ],\n                    }\n                ],\n            }\n        ],\n    }\n\n    # When\n    response = admin_client_new.put(\n        url, data=json.dumps(data), content_type="application/json"\n    )\n    # Then\n    assert response.status_code == status.HTTP_200_OK\n    assert response.json()["rules"][0]["type"] == "ANY"\n    assert response.json()["rules"][0]["rules"][0]["type"] == "ALL"\n    assert response.json()["rules"][0]["rules"][0]["conditions"][0]["property"] == "foo"\n    assert (\n        response.json()["rules"][0]["rules"][0]["conditions"][0]["operator"] == "EQUAL"\n    )\n    assert response.json()["rules"][0]["rules"][0]["conditions"][0]["value"] == "bar"\n\n\ndef test_update_segment_add_new_rule(\n    project: Project,\n    admin_client_new: APIClient,\n    segment: Segment,\n    segment_rule: SegmentRule,\n    settings: SettingsWrapper,\n) -> None:\n    # Given\n    settings.SEGMENT_RULES_CONDITIONS_EXPLICIT_ORDERING_ENABLED = True\n\n    url = reverse(\n        "api-v1:projects:project-segments-detail", args=[project.id, segment.id]\n    )\n    nested_rule = SegmentRule.objects.create(\n        rule=segment_rule, type=SegmentRule.ANY_RULE\n    )\n    existing_condition = Condition.objects.create(\n        rule=nested_rule, property="foo", operator=EQUAL, value="bar"\n    )\n\n    data = {\n        "name": segment.name,\n        "project": project.id,\n        "rules": [\n            {\n                "id": segment_rule.id,\n                "type": segment_rule.type,\n                "rules": [\n                    {\n                        "id": nested_rule.id,\n                        "type": nested_rule.type,\n                        "rules": [],\n                        "conditions": [\n                            {\n                                "id": existing_condition.id,\n                                "property": existing_condition.property,\n                                "operator": existing_condition.operator,\n                                "value": existing_condition.value,\n                            },\n                        ],\n                    },\n                    {  # New rule\n                        "type": SegmentRule.ANY_RULE,\n                        "rules": [],\n                        "conditions": [\n                            {\n                                "property": "foo",\n                                "operator": EQUAL,\n                                "value": "bar",\n                            },\n                        ],\n                    },\n                ],\n                "conditions": [],\n            }\n        ],\n    }\n\n    # When\n    response = admin_client_new.put(\n        url, data=json.dumps(data), content_type="application/json"\n    )\n\n    # Then\n    assert response.status_code == status.HTTP_200_OK\n    assert response.json()["rules"][0]["rules"][1]["type"] == SegmentRule.ANY_RULE\n    assert response.json()["rules"][0]["rules"][1]["conditions"][0]["property"] == "foo"\n    assert response.json()["rules"][0]["rules"][1]["conditions"][0]["operator"] == EQUAL\n    assert response.json()["rules"][0]["rules"][1]["conditions"][0]["value"] == "bar"\n\n    assert segment_rule.rules.count() == 2\n\n\ndef test_update_segment_add_new_condition(\n    project: Project,\n    admin_client_new: APIClient,\n    segment: Segment,\n    segment_rule: SegmentRule,\n    settings: SettingsWrapper,\n) -> None:\n    # Given\n    settings.SEGMENT_RULES_CONDITIONS_EXPLICIT_ORDERING_ENABLED = True\n\n    url = reverse(\n        "api-v1:projects:project-segments-detail", args=[project.id, segment.id]\n    )\n    nested_rule = SegmentRule.objects.create(\n        rule=segment_rule, type=SegmentRule.ANY_RULE\n    )\n    existing_condition = Condition.objects.create(\n        rule=nested_rule, property="foo", operator=EQUAL, value="bar"\n    )\n\n    new_condition_property = "foo2"\n    new_condition_value = "bar"\n    data = {\n        "name": segment.name,\n        "project": project.id,\n        "rules": [\n            {\n                "id": segment_rule.id,\n                "type": segment_rule.type,\n                "rules": [\n                    {\n                        "id": nested_rule.id,\n                        "type": nested_rule.type,\n                        "rules": [],\n                        "conditions": [\n                            # existing condition\n                            {\n                                "id": existing_condition.id,\n                                "property": existing_condition.property,\n                                "operator": existing_condition.operator,\n                                "value": existing_condition.value,\n                            },\n                            # new condition\n                            {\n                                "property": new_condition_property,\n                                "operator": EQUAL,\n                                "value": new_condition_value,\n                            },\n                        ],\n                    }\n                ],\n                "conditions": [],\n            }\n        ],\n    }\n\n    # When\n    response = admin_client_new.put(\n        url, data=json.dumps(data), content_type="application/json"\n    )\n\n    # Then\n    assert response.status_code == status.HTTP_200_OK\n\n    assert nested_rule.conditions.count() == 2\n    assert (expected_new_condition := nested_rule.conditions.last())\n    assert expected_new_condition.property == new_condition_property\n    assert expected_new_condition.value == new_condition_value\n\n\ndef test_update_segment_delete_and_update_existing_condition(\n    project: Project,\n    admin_client_new: APIClient,\n    segment: Segment,\n    segment_rule: SegmentRule,\n    settings: SettingsWrapper,\n) -> None:\n    # Given\n    settings.SEGMENT_RULES_CONDITIONS_EXPLICIT_ORDERING_ENABLED = True\n\n    url = reverse(\n        "api-v1:projects:project-segments-detail", args=[project.id, segment.id]\n    )\n    nested_rule = SegmentRule.objects.create(\n        rule=segment_rule, type=SegmentRule.ANY_RULE\n    )\n    existing_condition = Condition.objects.create(\n        rule=nested_rule, property="foo", operator=EQUAL, value="bar"\n    )\n    new_condition = Condition.objects.create(\n        rule=nested_rule, property="foo2", operator=EQUAL, value="bar2"\n    )\n\n    new_condition_updated_property = "foo3"\n    new_condition_updated_value = "bar3"\n    data = {\n        "name": segment.name,\n        "project": project.id,\n        "rules": [\n            {\n                "id": segment_rule.id,\n                "type": segment_rule.type,\n                "rules": [\n                    {\n                        "id": nested_rule.id,\n                        "type": nested_rule.type,\n                        "rules": [],\n                        "conditions": [\n                            {\n                                "id": existing_condition.id,\n                                "delete": True,\n                                "property": existing_condition.property,\n                                "operator": existing_condition.operator,\n                                "value": existing_condition.value,\n                            },\n                            {\n                                "id": new_condition.id,\n                                "property": new_condition_updated_property,\n                                "operator": new_condition.operator,\n                                "value": new_condition_updated_value,\n                            },\n                        ],\n                    }\n                ],\n                "conditions": [],\n            }\n        ],\n    }\n\n    # When\n    response = admin_client_new.put(\n        url, data=json.dumps(data), content_type="application/json"\n    )\n\n    # Then\n    assert response.status_code == status.HTTP_200_OK\n\n    assert nested_rule.conditions.count() == 1\n    assert (expected_new_condition := nested_rule.conditions.first())\n    assert expected_new_condition.property == new_condition_updated_property\n    assert expected_new_condition.value == new_condition_updated_value\n\n\ndef test_can_not_update_system_segment(\n    project: Project,\n    admin_client_new: APIClient,\n    system_segment: Segment,\n) -> None:\n    # Given\n    url = reverse(\n        "api-v1:projects:project-segments-detail", args=[project.id, system_segment.id]\n    )\n    data = {\n        "name": system_segment.name,\n        "project": project.id,\n        "description": "Updated description",\n        "rules": [],\n    }\n\n    # When\n    response = admin_client_new.put(\n        url, data=json.dumps(data), content_type="application/json"\n    )\n\n    # Then\n    assert response.status_code == status.HTTP_404_NOT_FOUND\n\n\ndef test_update_segment_versioned_segment(\n    project: Project,\n    admin_client_new: APIClient,\n    segment: Segment,\n    segment_rule: SegmentRule,\n) -> None:\n    # Given\n    url = reverse(\n        "api-v1:projects:project-segments-detail", args=[project.id, segment.id]\n    )\n    nested_rule = SegmentRule.objects.create(\n        rule=segment_rule, type=SegmentRule.ANY_RULE\n    )\n    existing_condition = Condition.objects.create(\n        rule=nested_rule, property="foo", operator=EQUAL, value="bar"\n    )\n\n    new_condition_property = "foo2"\n    new_condition_value = "bar"\n    data = {\n        "name": segment.name,\n        "project": project.id,\n        "rules": [\n            {\n                "id": segment_rule.id,\n                "type": segment_rule.type,\n                "rules": [\n                    {\n                        "id": nested_rule.id,\n                        "type": nested_rule.type,\n                        "rules": [],\n                        "conditions": [\n                            # existing condition\n                            {\n                                "id": existing_condition.id,\n                                "property": existing_condition.property,\n                                "operator": existing_condition.operator,\n                                "value": existing_condition.value,\n                            },\n                            # new condition\n                            {\n                                "property": new_condition_property,\n                                "operator": EQUAL,\n                                "value": new_condition_value,\n                            },\n                        ],\n                    }\n                ],\n                "conditions": [],\n            }\n        ],\n    }\n\n    # When\n    response = admin_client_new.put(\n        url, data=json.dumps(data), content_type="application/json"\n    )\n\n    # Then\n    assert response.status_code == status.HTTP_200_OK\n\n    # Now verify that a new versioned segment has been set.\n    assert Segment.objects.filter(version_of=segment).count() == 2\n\n    # Now check the previously versioned segment to match former count of conditions.\n\n    versioned_segment = Segment.objects.filter(version_of=segment, version=1).first()\n    assert versioned_segment != segment\n    assert versioned_segment.rules.count() == 1\n    versioned_rule = versioned_segment.rules.first()\n    assert versioned_rule.rules.count() == 1\n\n    nested_versioned_rule = versioned_rule.rules.first()\n    assert nested_versioned_rule.conditions.count() == 1\n    versioned_condition = nested_versioned_rule.conditions.first()\n    assert versioned_condition != existing_condition\n    assert versioned_condition.property == existing_condition.property\n\n\ndef test_update_segment_versioned_segment_with_thrown_exception(\n    project: Project,\n    admin_client_new: APIClient,\n    segment: Segment,\n    segment_rule: SegmentRule,\n    mocker: MockerFixture,\n) -> None:\n    # Given\n    url = reverse(\n        "api-v1:projects:project-segments-detail", args=[project.id, segment.id]\n    )\n    nested_rule = SegmentRule.objects.create(\n        rule=segment_rule, type=SegmentRule.ANY_RULE\n    )\n    existing_condition = Condition.objects.create(\n        rule=nested_rule, property="foo", operator=EQUAL, value="bar"\n    )\n\n    assert segment.version == 1 == Segment.objects.filter(version_of=segment).count()\n\n    new_condition_property = "foo2"\n    new_condition_value = "bar"\n    data = {\n        "name": segment.name,\n        "project": project.id,\n        "rules": [\n            {\n                "id": segment_rule.id,\n                "type": segment_rule.type,\n                "rules": [\n                    {\n                        "id": nested_rule.id,\n                        "type": nested_rule.type,\n                        "rules": [],\n                        "conditions": [\n                            {\n                                "id": existing_condition.id,\n                                "property": existing_condition.property,\n                                "operator": existing_condition.operator,\n                                "value": existing_condition.value,\n                            },\n                            {\n                                "property": new_condition_property,\n                                "operator": EQUAL,\n                                "value": new_condition_value,\n                            },\n                        ],\n                    }\n                ],\n                "conditions": [],\n            }\n        ],\n    }\n\n    update_super_patch = mocker.patch(\n        "rest_framework.serializers.ModelSerializer.update"\n    )\n    update_super_patch.side_effect = Exception("Mocked exception")\n\n    # When\n    with pytest.raises(Exception):\n        admin_client_new.put(\n            url, data=json.dumps(data), content_type="application/json"\n        )\n\n    # Then\n    segment.refresh_from_db()\n\n    # Now verify that the version of the segment has not been changed.\n    assert segment.version == 1 == Segment.objects.filter(version_of=segment).count()\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_update_segment_delete_existing_condition(  # type: ignore[no-untyped-def]\n    project, client, segment, segment_rule\n):\n    # Given\n    url = reverse(\n        "api-v1:projects:project-segments-detail", args=[project.id, segment.id]\n    )\n    nested_rule = SegmentRule.objects.create(\n        rule=segment_rule, type=SegmentRule.ANY_RULE\n    )\n    existing_condition = Condition.objects.create(\n        rule=nested_rule, property="foo", operator=EQUAL, value="bar"\n    )\n\n    data = {\n        "name": segment.name,\n        "project": project.id,\n        "rules": [\n            {\n                "id": segment_rule.id,\n                "type": segment_rule.type,\n                "rules": [\n                    {\n                        "id": nested_rule.id,\n                        "type": nested_rule.type,\n                        "rules": [],\n                        "conditions": [\n                            {\n                                "id": existing_condition.id,\n                                "property": existing_condition.property,\n                                "operator": existing_condition.operator,\n                                "value": existing_condition.value,\n                                "delete": True,\n                            },\n                        ],\n                    }\n                ],\n                "conditions": [],\n            }\n        ],\n    }\n\n    # When\n    response = client.put(url, data=json.dumps(data), content_type="application/json")\n\n    # Then\n    assert response.status_code == status.HTTP_200_OK\n    assert nested_rule.conditions.count() == 0\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_update_segment_delete_existing_rule(project, client, segment, segment_rule):  # type: ignore[no-untyped-def]\n    # Given\n    url = reverse(\n        "api-v1:projects:project-segments-detail", args=[project.id, segment.id]\n    )\n    nested_rule = SegmentRule.objects.create(\n        rule=segment_rule, type=SegmentRule.ANY_RULE\n    )\n\n    data = {\n        "name": segment.name,\n        "project": project.id,\n        "rules": [\n            {\n                "id": segment_rule.id,\n                "type": segment_rule.type,\n                "rules": [\n                    {\n                        "id": nested_rule.id,\n                        "type": nested_rule.type,\n                        "rules": [],\n                        "conditions": [],\n                        "delete": True,\n                    }\n                ],\n                "conditions": [],\n            }\n        ],\n    }\n\n    # When\n    response = client.put(url, data=json.dumps(data), content_type="application/json")\n    # Then\n    assert response.status_code == status.HTTP_200_OK\n\n    assert nested_rule.conditions.count() == 0\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_update_segment_metadata_create_correct_number_of_metadata(\n    project: Project,\n    client: APIClient,\n    required_a_segment_metadata_field: MetadataModelField,\n) -> None:\n    # Given\n    url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n    description = "This is the description"\n    field_value = 10\n    first_segment_data = {\n        "name": "Test Segment",\n        "description": description,\n        "project": project.id,\n        "rules": [{"type": "ALL", "rules": [], "conditions": []}],\n        "metadata": [\n            {\n                "model_field": required_a_segment_metadata_field.id,\n                "field_value": field_value,\n            },\n        ],\n    }\n    second_segment_data = {\n        "name": "Test Segment",\n        "description": description,\n        "project": project.id,\n        "rules": [{"type": "ALL", "rules": [], "conditions": []}],\n        "metadata": [\n            {\n                "model_field": required_a_segment_metadata_field.id,\n                "field_value": field_value,\n            },\n        ],\n    }\n\n    # When\n    response_first = client.post(\n        url, data=json.dumps(first_segment_data), content_type="application/json"\n    )\n    response_second = client.post(\n        url, data=json.dumps(second_segment_data), content_type="application/json"\n    )\n    # Then\n    assert response_first.status_code == status.HTTP_201_CREATED\n    assert response_second.status_code == status.HTTP_201_CREATED\n    assert (\n        response_first.json()["metadata"][0]["model_field"]\n        == required_a_segment_metadata_field.id\n    )\n    assert (\n        response_second.json()["metadata"][0]["model_field"]\n        == required_a_segment_metadata_field.id\n    )\n\n    metadata = Metadata.objects.filter(\n        model_field=required_a_segment_metadata_field.id\n    ).all()\n    assert metadata.count() == 2\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_create_segment_with_required_metadata_returns_201(\n    project: Project,\n    client: APIClient,\n    required_a_segment_metadata_field: MetadataModelField,\n) -> None:\n    # Given\n    url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n    description = "This is the description"\n    field_value = 10\n    data = {\n        "name": "Test Segment",\n        "description": description,\n        "project": project.id,\n        "rules": [{"type": "ALL", "rules": [], "conditions": []}],\n        "metadata": [\n            {\n                "model_field": required_a_segment_metadata_field.id,\n                "field_value": field_value,\n            },\n        ],\n    }\n\n    # When\n    response = client.post(url, data=json.dumps(data), content_type="application/json")\n\n    # Then\n    assert response.status_code == status.HTTP_201_CREATED\n    assert (\n        response.json()["metadata"][0]["model_field"]\n        == required_a_segment_metadata_field.id\n    )\n    assert response.json()["metadata"][0]["field_value"] == str(field_value)\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_create_segment_with_required_metadata_using_organisation_content_type_returns_201(\n    project: Project,\n    client: APIClient,\n    required_a_segment_metadata_field_using_organisation_content_type: MetadataModelField,\n) -> None:\n    # Given\n    url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n    description = "This is the description"\n    field_value = 10\n    data = {\n        "name": "Test Segment",\n        "description": description,\n        "project": project.id,\n        "rules": [{"type": "ALL", "rules": [], "conditions": []}],\n        "metadata": [\n            {\n                "model_field": required_a_segment_metadata_field_using_organisation_content_type.id,\n                "field_value": field_value,\n            },\n        ],\n    }\n\n    # When\n    response = client.post(url, data=json.dumps(data), content_type="application/json")\n\n    # Then\n    assert response.status_code == status.HTTP_201_CREATED\n    assert (\n        response.json()["metadata"][0]["model_field"]\n        == required_a_segment_metadata_field_using_organisation_content_type.id\n    )\n    assert response.json()["metadata"][0]["field_value"] == str(field_value)\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_create_segment_without_required_metadata_returns_400(\n    project: Project,\n    client: APIClient,\n    required_a_segment_metadata_field: MetadataModelField,\n) -> None:\n    # Given\n    url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n    description = "This is the description"\n    data = {\n        "name": "Test Segment",\n        "description": description,\n        "project": project.id,\n        "rules": [{"type": "ALL", "rules": [], "conditions": []}],\n    }\n\n    # When\n    response = client.post(url, data=json.dumps(data), content_type="application/json")\n\n    # Then\n    assert response.status_code == status.HTTP_400_BAD_REQUEST\n\n\ndef test_update_segment_obeys_max_conditions(\n    project: Project,\n    admin_client: APIClient,\n    segment: Segment,\n    segment_rule: SegmentRule,\n    settings: SettingsWrapper,\n) -> None:\n    # Given\n    url = reverse(\n        "api-v1:projects:project-segments-detail", args=[project.id, segment.id]\n    )\n    nested_rule = SegmentRule.objects.create(\n        rule=segment_rule, type=SegmentRule.ANY_RULE\n    )\n    existing_condition = Condition.objects.create(\n        rule=nested_rule, property="foo", operator=EQUAL, value="bar"\n    )\n\n    # Reduce value for test debugging.\n    settings.SEGMENT_RULES_CONDITIONS_LIMIT = 10\n    new_condition_property = "prop_"\n    new_condition_value = "red"\n    new_conditions = []\n    for i in range(settings.SEGMENT_RULES_CONDITIONS_LIMIT):\n        new_conditions.append(\n            {\n                "property": f"{new_condition_property}{i}",\n                "operator": EQUAL,\n                "value": new_condition_value,\n            }\n        )\n\n    data = {\n        "name": segment.name,\n        "project": project.id,\n        "rules": [\n            {\n                "id": segment_rule.id,\n                "type": segment_rule.type,\n                "rules": [\n                    {\n                        "id": nested_rule.id,\n                        "type": nested_rule.type,\n                        "rules": [],\n                        "conditions": [\n                            {\n                                "id": existing_condition.id,\n                                "property": existing_condition.property,\n                                "operator": existing_condition.operator,\n                                "value": existing_condition.value,\n                            },\n                            *new_conditions,\n                        ],\n                    }\n                ],\n                "conditions": [],\n            }\n        ],\n    }\n\n    # When\n    response = admin_client.put(\n        url, data=json.dumps(data), content_type="application/json"\n    )\n\n    # Then\n    assert response.status_code == status.HTTP_400_BAD_REQUEST\n    assert response.json() == {\n        "segment": [\n            "The segment has 11 conditions, which exceeds the maximum condition count of 10."\n        ]\n    }\n\n    nested_rule.refresh_from_db()\n    assert nested_rule.conditions.count() == 1\n\n\n@pytest.mark.parametrize(\n    "client",\n    [lazy_fixture("admin_master_api_key_client"), lazy_fixture("admin_client")],\n)\ndef test_create_segment_with_optional_metadata_returns_201(\n    project: Project,\n    client: APIClient,\n    optional_b_segment_metadata_field: MetadataModelField,\n) -> None:\n    # Given\n    url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n    description = "This is the description"\n    field_value = 10\n    data = {\n        "name": "Test Segment",\n        "description": description,\n        "project": project.id,\n        "rules": [{"type": "ALL", "rules": [], "conditions": []}],\n        "metadata": [\n            {\n                "model_field": optional_b_segment_metadata_field.id,\n                "field_value": field_value,\n            },\n        ],\n    }\n\n    # When\n    response = client.post(url, data=json.dumps(data), content_type="application/json")\n\n    # Then\n    assert response.status_code == status.HTTP_201_CREATED\n    assert (\n        response.json()["metadata"][0]["model_field"]\n        == optional_b_segment_metadata_field.id\n    )\n    assert response.json()["metadata"][0]["field_value"] == str(field_value)\n\n\ndef test_create_multiple_segments_with_metadata_keeps_metadata_isolated(\n    project: Project,\n    admin_client_new: APIClient,\n    optional_b_segment_metadata_field: MetadataModelField,\n) -> None:\n    """\n    Test that creating multiple segments with metadata keeps metadata properly isolated.\n    This is a regression test for the bug where creating a second segment would remove\n    metadata from the first segment if the user sent the first segment\'s metadata ID.\n    """\n    # Given\n    url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n\n    # Create first segment with metadata\n    first_segment_data = {\n        "name": "First Segment",\n        "description": "First segment description",\n        "project": project.id,\n        "rules": [{"type": "ALL", "rules": [], "conditions": []}],\n        "metadata": [\n            {\n                "model_field": optional_b_segment_metadata_field.id,\n                "field_value": "100",\n            },\n        ],\n    }\n\n    # When - Create first segment\n    first_response = admin_client_new.post(\n        url, data=json.dumps(first_segment_data), content_type="application/json"\n    )\n\n    # Then - First segment should be created successfully\n    assert first_response.status_code == status.HTTP_201_CREATED\n    first_segment_id = first_response.json()["id"]\n    first_metadata = first_response.json()["metadata"]\n    assert len(first_metadata) == 1\n    assert first_metadata[0]["field_value"] == "100"\n    first_metadata_id = first_metadata[0]["id"]\n\n    # Given - Create second segment\n    second_segment_data = {\n        "name": "Second Segment",\n        "description": "Second segment description",\n        "project": project.id,\n        "rules": [{"type": "ALL", "rules": [], "conditions": []}],\n        "metadata": [\n            {\n                "id": first_metadata_id,  # user mistakenly sends existing metadata ID\n                "model_field": optional_b_segment_metadata_field.id,\n                "field_value": "200",\n            },\n        ],\n    }\n\n    # When - Create second segment\n    second_response = admin_client_new.post(\n        url, data=json.dumps(second_segment_data), content_type="application/json"\n    )\n\n    # Then - Second segment should be created successfully\n    assert second_response.status_code == status.HTTP_201_CREATED\n    second_segment_id = second_response.json()["id"]\n    second_metadata = second_response.json()["metadata"]\n    assert len(second_metadata) == 1\n    assert second_metadata[0]["field_value"] == "200"\n    # The metadata ID should be different (new metadata instance created)\n    assert second_metadata[0]["id"] != first_metadata_id\n\n    # When - Retrieve first segment to verify metadata is still there\n    first_segment_url = reverse(\n        "api-v1:projects:project-segments-detail", args=[project.id, first_segment_id]\n    )\n    first_segment_check = admin_client_new.get(first_segment_url)\n\n    # Then - First segment should still have its metadata\n    assert first_segment_check.status_code == status.HTTP_200_OK\n    first_segment_metadata_after = first_segment_check.json()["metadata"]\n    assert len(first_segment_metadata_after) == 1\n    assert first_segment_metadata_after[0]["field_value"] == "100"\n    assert first_segment_metadata_after[0]["id"] == first_metadata_id\n\n    # When - Retrieve second segment to verify metadata\n    second_segment_url = reverse(\n        "api-v1:projects:project-segments-detail", args=[project.id, second_segment_id]\n    )\n    second_segment_check = admin_client_new.get(second_segment_url)\n\n    # Then - Second segment should have its own metadata\n    assert second_segment_check.status_code == status.HTTP_200_OK\n    second_segment_metadata_after = second_segment_check.json()["metadata"]\n    assert len(second_segment_metadata_after) == 1\n    assert second_segment_metadata_after[0]["field_value"] == "200"\n    assert second_segment_metadata_after[0]["id"] != first_metadata_id\n\n\ndef test_update_segment_evades_max_conditions_when_whitelisted(\n    project: Project,\n    admin_client: APIClient,\n    segment: Segment,\n    segment_rule: SegmentRule,\n    settings: SettingsWrapper,\n) -> None:\n    # Given\n    url = reverse(\n        "api-v1:projects:project-segments-detail", args=[project.id, segment.id]\n    )\n    nested_rule = SegmentRule.objects.create(\n        rule=segment_rule, type=SegmentRule.ANY_RULE\n    )\n    existing_condition = Condition.objects.create(\n        rule=nested_rule, property="foo", operator=EQUAL, value="bar"\n    )\n\n    # Create the whitelist to stop the validation.\n    WhitelistedSegment.objects.create(segment=segment)\n\n    # Reduce value for test debugging.\n    settings.SEGMENT_RULES_CONDITIONS_LIMIT = 10\n    new_condition_property = "prop_"\n    new_condition_value = "red"\n    new_conditions = []\n    for i in range(settings.SEGMENT_RULES_CONDITIONS_LIMIT):\n        new_conditions.append(\n            {\n                "property": f"{new_condition_property}{i}",\n                "operator": EQUAL,\n                "value": new_condition_value,\n            }\n        )\n\n    data = {\n        "name": segment.name,\n        "project": project.id,\n        "rules": [\n            {\n                "id": segment_rule.id,\n                "type": segment_rule.type,\n                "rules": [\n                    {\n                        "id": nested_rule.id,\n                        "type": nested_rule.type,\n                        "rules": [],\n                        "conditions": [\n                            {\n                                "id": existing_condition.id,\n                                "property": existing_condition.property,\n                                "operator": existing_condition.operator,\n                                "value": existing_condition.value,\n                            },\n                            *new_conditions,\n                        ],\n                    }\n                ],\n                "conditions": [],\n            }\n        ],\n    }\n\n    # When\n    response = admin_client.put(\n        url, data=json.dumps(data), content_type="application/json"\n    )\n\n    # Then\n    assert response.status_code == status.HTTP_200_OK\n    nested_rule.refresh_from_db()\n    assert nested_rule.conditions.count() == 11\n\n\ndef test_create_segment_obeys_max_conditions(\n    project: Project,\n    admin_client: APIClient,\n    settings: SettingsWrapper,\n) -> None:\n    # Given\n    url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n\n    # Reduce value for test debugging.\n    settings.SEGMENT_RULES_CONDITIONS_LIMIT = 10\n    new_condition_property = "prop_"\n    new_condition_value = "red"\n    new_conditions = []\n    for i in range(settings.SEGMENT_RULES_CONDITIONS_LIMIT + 1):\n        new_conditions.append(\n            {\n                "property": f"{new_condition_property}{i}",\n                "operator": EQUAL,\n                "value": new_condition_value,\n            }\n        )\n\n    data = {\n        "name": "segment_name",\n        "project": project.id,\n        "rules": [\n            {\n                "conditions": [],\n                "type": "ALL",\n                "rules": [\n                    {\n                        "type": "ANY",\n                        "rules": [],\n                        "conditions": [\n                            *new_conditions,\n                        ],\n                    }\n                ],\n            }\n        ],\n    }\n\n    # When\n    response = admin_client.post(\n        url, data=json.dumps(data), content_type="application/json"\n    )\n\n    # Then\n    assert response.status_code == status.HTTP_400_BAD_REQUEST\n    assert response.json() == {\n        "segment": [\n            "The segment has 11 conditions, which exceeds the maximum condition count of 10."\n        ]\n    }\n    assert Segment.objects.count() == 0\n\n\ndef test_include_feature_specific_query_filter__true(\n    staff_client: APIClient,\n    with_project_permissions: WithProjectPermissionsCallable,\n    project: Project,\n    segment: Segment,\n    feature_specific_segment: Segment,\n) -> None:\n    # Given\n    with_project_permissions([MANAGE_SEGMENTS, VIEW_PROJECT])  # type: ignore[call-arg]\n    url = "%s?include_feature_specific=1" % (\n        reverse("api-v1:projects:project-segments-list", args=[project.id]),\n    )\n\n    # When\n    response = staff_client.get(url)\n\n    # Then\n    assert response.json()["count"] == 2\n    assert [res["id"] for res in response.json()["results"]] == [\n        segment.id,\n        feature_specific_segment.id,\n    ]\n\n\ndef test_include_feature_specific_query_filter__false(\n    staff_client: APIClient,\n    with_project_permissions: WithProjectPermissionsCallable,\n    project: Project,\n    segment: Segment,\n    feature_specific_segment: Segment,\n) -> None:\n    # Given\n    with_project_permissions([MANAGE_SEGMENTS, VIEW_PROJECT])  # type: ignore[call-arg]\n    url = "%s?include_feature_specific=0" % (\n        reverse("api-v1:projects:project-segments-list", args=[project.id]),\n    )\n\n    # When\n    response = staff_client.get(url)\n\n    # Then\n    assert response.json()["count"] == 1\n    assert [res["id"] for res in response.json()["results"]] == [segment.id]\n\n\ndef test_clone_endpoint_uses_segment_clone_service(\n    project: Project,\n    admin_client: APIClient,\n    segment: Segment,\n    mocker: MockerFixture,\n) -> None:\n    # Given\n    url = reverse(\n        "api-v1:projects:project-segments-clone", args=[project.id, segment.id]\n    )\n    new_segment_name = "cloned_segment"\n    data = {\n        "name": new_segment_name,\n    }\n    # When\n    response = admin_client.post(\n        url, data=json.dumps(data), content_type="application/json"\n    )\n\n    # Then\n    assert response.status_code == status.HTTP_201_CREATED\n\n    response_data = response.json()\n    assert response_data["name"] == new_segment_name\n    assert response_data["project"] == project.id\n    assert response_data["id"] != segment.id\n\n\ndef test_clone_segment_without_name_should_fail(\n    project: Project,\n    admin_client: APIClient,\n    segment: Segment,\n) -> None:\n    # Given\n    url = reverse(\n        "api-v1:projects:project-segments-clone", args=[project.id, segment.id]\n    )\n    data = {\n        "no-name": "",\n    }\n    # When\n    response = admin_client.post(\n        url, data=json.dumps(data), content_type="application/json"\n    )\n\n    # Then\n    assert response.status_code == status.HTTP_400_BAD_REQUEST\n\n\ndef test_create_segment__required_metadata_on_other_project__returns_201(\n    admin_client: APIClient,\n    project: Project,\n    project_b: Project,\n    organisation: Organisation,\n    a_metadata_field: MetadataField,\n    segment_content_type: ContentType,\n    project_content_type: ContentType,\n) -> None:\n    # Given\n    model_field = MetadataModelField.objects.create(\n        field=a_metadata_field,\n        content_type=segment_content_type,\n    )\n    MetadataModelFieldRequirement.objects.create(\n        content_type=project_content_type,\n        object_id=project_b.id,\n        model_field=model_field,\n    )\n    url = reverse("api-v1:projects:project-segments-list", args=[project.id])\n    data = {\n        "name": "Test segment cross project",\n        "project": project.id,\n        "rules": [{"type": "ALL", "rules": [], "conditions": []}],\n    }\n\n    # When\n    response = admin_client.post(\n        url, data=json.dumps(data), content_type="application/json"\n    )\n\n    # Then\n    assert response.status_code == status.HTTP_201_CREATED\n',
        }
